Array.prototype.snail = function(rowsCount, colsCount) {
    if (rowsCount * colsCount !== this.length) return [];

    const res = Array.from({ length: rowsCount }, () => Array(colsCount));
    for (let i = 0; i < this.length; i++) {
        const col = Math.floor(i / rowsCount);
        const row = col % 2 === 0 ? (i % rowsCount) : (rowsCount - 1 - (i % rowsCount));
        res[row][col] = this[i];
    }
    return res;
}

/**
 * @param {Array} arr
 * @param {number} depth
 * @return {Array}
 */
var flat = function(arr, n) {
    if (n === 0) return arr;

    const res = [];
    function flatten(currArr, currDepth) {
        for (const item of currArr) {
            if (Array.isArray(item) && currDepth < n) {
                flatten(item, currDepth + 1);
            } else {
                res.push(item);
            }
        }
    }

    flatten(arr, 0);
    return res;
};

/**
