/**
 * @param {Object} context
 * @param {Array} args
 * @return {any}
 */
Function.prototype.callPolyfill = function(context, ...args) {
    const fnKey = Symbol();
    context[fnKey] = this;
    const result = context[fnKey](...args);
    delete context[fnKey];
    return result;
};

