var join = function(arr1, arr2) {
    const res = new Map();
    for (const obj of arr1) res.set(obj.id, obj);
    for (const obj of arr2) {
        if (res.has(obj.id)) {
            res.set(obj.id, { ...res.get(obj.id), ...obj });
        } else {
            res.set(obj.id, obj);
        }
    }
    return Array.from(res.values()).sort((a, b) => a.id - b.id);
};

