        dp = collections.defaultdict(int)
        for x in nums:
            # We can pick x or x+1
            # Case 1: Use x+1 to extend a sequence ending in x
            dp[x+1] = dp[x] + 1
            # Case 2: Use x to extend a sequence ending in x-1
            dp[x] = dp[x-1] + 1
        return max(dp.values())

