    def maximumValueSum(self, board: List[List[int]]) -> int:
        # Find 3 cells in different rows and columns with max sum
        # Keep top 3 values in each row
        m, n = len(board), len(board[0])
        top3 = []
        for r in range(m):
            row = sorted([(board[r][c], c) for c in range(n)], reverse=True)[:3]
            top3.append(row)

        # Try all 3-row combinations
        ans = -float('inf')
        for r1 in range(m):
            for r2 in range(r1 + 1, m):
                for r3 in range(r2 + 1, m):
                    # Try top values for these 3 rows
                    for v1, c1 in top3[r1]:
                        for v2, c2 in top3[r2]:
                            if c2 == c1: continue
                            for v3, c3 in top3[r3]:
                                if c3 == c1 or c3 == c2: continue
                                ans = max(ans, v1 + v2 + v3)
        return ans

