class Solution:
    def maxPathLength(self, coordinates: List[List[int]], k: int) -> int:
        # Longest increasing subsequence in 2D
        # Must include the k-th point
        target = coordinates[k]

        # Split points into two groups: before target and after target
        before = [p for p in coordinates if p[0] < target[0] and p[1] < target[1]]
        after = [p for p in coordinates if p[0] > target[0] and p[1] > target[1]]

        def lis(pts):
            if not pts: return 0
            # Sort by x ascending, then y descending
            pts.sort(key=lambda p: (p[0], -p[1]))
            # LIS on y
            tails = []
            for _, y in pts:
                idx = bisect.bisect_left(tails, y)
                if idx == len(tails): tails.append(y)
                else: tails[idx] = y
            return len(tails)

        return lis(before) + 1 + lis(after)

