        n = len(nums)
        ans = float('inf')
        for length in range(l, r + 1):
            # Sliding window for current length
            curr_sum = sum(nums[:length])
            if curr_sum > 0: ans = min(ans, curr_sum)
            for i in range(length, n):
                curr_sum += nums[i] - nums[i - length]
                if curr_sum > 0: ans = min(ans, curr_sum)
