        return res

class Solution:
    def minMaxWeight(self, n: int, edges: List[List[int]], threshold: int) -> int:
        # Binary search on the weight W
        # For a given W, check if node 0 is reachable from all other nodes
        # (In other words, are all nodes reachable from 0 in inverted graph)
        adj = collections.defaultdict(list)
        for u, v, w in edges:
            adj[v].append((u, w)) # Inverted

        def check(max_w):
            visited = {0}
            q = collections.deque([0])
            while q:
                u = q.popleft()
                for v, w in adj[u]:
                    if w <= max_w and v not in visited:
                        visited.add(v)
                        q.append(v)
            return len(visited) == n

        low = 1
        high = max(e[2] for e in edges)
        ans = -1
        while low <= high:
            mid = (low + high) // 2
            if check(mid):
                ans = mid
                high = mid - 1
            else:
                low = mid + 1
        return ans

