                g = gcd(c, d)
                cnt[(d // g, c // g)] -= 1
        return ans

class Solution:
    def countKReducibleNumbers(self, s: str, k: int) -> int:
        # Precompute reductions for all possible bit counts (up to 800)
        n = len(s)
        MOD = 10**9 + 7

        memo_red = {1: 0}
        def get_red(x):
            if x in memo_red: return memo_red[x]
            memo_red[x] = 1 + get_red(bin(x).count('1'))
            return memo_red[x]

        valid_bit_counts = []
        for b in range(1, n + 1):
            if get_red(b) < k:
                valid_bit_counts.append(b)

        # Digit DP to count numbers < s with specific bit counts
        @functools.lru_cache(None)
        def dp(idx, count, is_less):
            if idx == n:
                return 1 if count in valid_bit_counts else 0

            res = 0
            limit = int(s[idx]) if not is_less else 1
            for digit in range(limit + 1):
                res = (res + dp(idx + 1, count + digit, is_less or (digit < limit))) % MOD
            return res

        # Subtract 1 because we only want positive integers
        return (dp(0, 0, False) - 1 + MOD) % MOD

