    def countPaths(self, grid: List[List[int]], k: int) -> int:
        # DP: dp[r][c][xor_val] = number of paths to (r,c) with XOR sum xor_val
        m, n = len(grid), len(grid[0])
        MOD = 10**9 + 7
        dp = [[collections.defaultdict(int) for _ in range(n)] for _ in range(m)]
        dp[0][0][grid[0][0]] = 1
        for r in range(m):
            for c in range(n):
                for val, count in dp[r][c].items():
                    if r + 1 < m:
                        nxt = val ^ grid[r+1][c]
                        dp[r+1][c][nxt] = (dp[r+1][c][nxt] + count) % MOD
                    if c + 1 < n:
                        nxt = val ^ grid[r][c+1]
                        dp[r][c+1][nxt] = (dp[r][c+1][nxt] + count) % MOD
        return dp[m-1][n-1][k]

