class Solution:
    def pathSum(self, root: Optional[TreeNode], targetSum: int) -> int:
        counts = collections.defaultdict(int)
        counts[0] = 1
        def dfs(node, curr):
            if not node: return 0
            curr += node.val
            res = counts[curr - targetSum]
            counts[curr] += 1
            res += dfs(node.left, curr) + dfs(node.right, curr)
            counts[curr] -= 1
            return res
        return dfs(root, 0)

